```python
def parse_config(input_str):
    parts = input_str.split(' = ')
    if len(parts) != 2 or not parts[0].startswith("SET "):
        raise ValueError("Invalid config format.")

    target = parts[0][4:].strip()
    raw_value = parts[1].strip()

    if raw_value.startswith("'") and raw_value.endswith("'"):
        value = raw_value.strip("'")
        value_node = {"type": "string", "value": value}
    else:
        try:
            value = int(raw_value)
            value_node = {"type": "integer", "value": value}
        except ValueError:
            raise ValueError(f"Invalid value format: {raw_value}")

    return {
        "type": "assignment",
        "target": target,
        "value": value_node
    }

